<?php
require_once __DIR__.'/app/layout.php'; require_login();
$admin=is_admin(); $own=$admin?null:require_operator_employee_id();
if($admin){$emps=db()->query('SELECT id,name FROM employees WHERE active=1 ORDER BY name')->fetchAll();$employee=(int)($_GET['employee_id']??($emps[0]['id']??0));}
else{$employee=$own;$st=db()->prepare('SELECT id,name FROM employees WHERE id=?');$st->execute([$own]);$emps=$st->fetchAll();}
$month=(int)($_GET['month']??date('n'));$year=(int)($_GET['year']??date('Y'));$start=sprintf('%04d-%02d-01',$year,$month);$end=date('Y-m-t',strtotime($start));$st=db()->prepare('SELECT * FROM attendance_events WHERE employee_id=? AND event_date BETWEEN ? AND ? ORDER BY event_date');$st->execute([$employee,$start,$end]);$events=[];foreach($st as $r)$events[$r['event_date']][]=$r;$count=array_sum(array_map('count',$events));$max=(int)(settings()['max_absences']??4);[$cls,$label,$msg]=count_status($count,$max);$first=(int)date('w',strtotime($start));$days=(int)date('t',strtotime($start));
page_header('Kalender Rekap','calendar');?><div class="card"><div class="section-title"><h2>Kalender Lupa Absen</h2><span class="badge <?=$cls?>"><?=e($msg)?></span></div><form class="form-grid" method="get" style="margin-bottom:14px"><div class="field"><label>Pegawai</label><?php if($admin):?><select name="employee_id"><?php foreach($emps as $e):?><option value="<?=$e['id']?>" <?=$employee===$e['id']?'selected':''?>><?=e($e['name'])?></option><?php endforeach;?></select><?php else:?><input value="<?=e($emps[0]['name']??'')?>" disabled><?php endif;?></div><div class="field"><label>Bulan</label><select name="month"><?php foreach(indo_months() as $m=>$name):?><option value="<?=$m?>" <?=$month===$m?'selected':''?>><?=e($name)?></option><?php endforeach;?></select></div><div class="field"><label>Tahun</label><select name="year"><?php for($y=date('Y')-2;$y<=date('Y')+3;$y++):?><option <?=$year==$y?'selected':''?>><?=$y?></option><?php endfor;?></select></div><div class="form-actions"><button class="btn secondary">Tampilkan</button></div></form><div class="calendar"><?php foreach(['Min','Sen','Sel','Rab','Kam','Jum','Sab'] as $d):?><div class="dow"><?=$d?></div><?php endforeach;?><?php for($i=0;$i<$first;$i++):?><div class="day muted"></div><?php endfor;?><?php for($d=1;$d<=$days;$d++):$date=sprintf('%04d-%02d-%02d',$year,$month,$d);?><div class="day"><div class="day-num"><?=$d?></div><?php foreach($events[$date]??[] as $ev):?><a class="cal-event <?=$count>$max?'over':''?>" href="letter.php?id=<?=$ev['id']?>"><?=e(category_codes()[$ev['category']].' '.substr($ev['event_time'],0,5))?></a><?php endforeach;?></div><?php endfor;?></div></div><?php page_footer();
